import json, pathlib

PROC_DIR = pathlib.Path("memory/procedures")
PROC_DIR.mkdir(parents=True, exist_ok=True)

def save_procedure(proc: Procedure) -> None:
    proc.updated_at = datetime.utcnow().isoformat()
    path = PROC_DIR / f"{proc.name}.json"
    # Serialise Steps to dicts
    data = proc.__dict__.copy()
    data["steps"] = [s.__dict__ for s in proc.steps]
    path.write_text(json.dumps(data, indent=2))

def load_procedure(name: str) -> Procedure | None:
    path = PROC_DIR / f"{name}.json"
    if not path.exists():
        return None
    data = json.loads(path.read_text())
    data["steps"] = [Step(**s) for s in data["steps"]]
    return Procedure(**data)

def list_procedures(tag: str | None = None) -> list[Procedure]:
    procs = []
    for f in sorted(PROC_DIR.glob("*.json")):
        proc = load_procedure(f.stem)
        if proc and (tag is None or tag in proc.tags):
            procs.append(proc)
    return procs

def find_procedure(query: str) -> Procedure | None:
    """Find the best-matching procedure by name or description keyword."""
    query_lower = query.lower()
    candidates = list_procedures()
    for proc in candidates:
        if query_lower in proc.name.lower() or query_lower in proc.description.lower():
            return proc
    return None

import anthropic

client = anthropic.Anthropic()

RUN_PROCEDURE_TOOL = {
    "name": "run_procedure",
    "description": "Execute a stored procedure by name.",
    "input_schema": {
        "type": "object",
        "properties": {
            "procedure_name": {"type": "string", "description": "Exact procedure name from the library."},
            "context": {
                "type": "object",
                "description": "Key-value substitution variables for procedure step arguments.",
            },
        },
        "required": ["procedure_name"],
    },
}

def build_procedure_menu() -> str:
    procs = list_procedures()
    if not procs:
        return ""
    lines = ["[AVAILABLE PROCEDURES]"]
    for p in procs:
        rate = f"{p.success_rate:.0%} success" if p.use_count else "new"
        lines.append(f"  • {p.name}: {p.description} ({rate})")
    return "\n".join(lines)

def agent_with_procedures(user_message: str, history: list[dict]) -> str:
    system = "You are a DevOps assistant.\n\n" + build_procedure_menu()
    messages = history + [{"role": "user", "content": user_message}]

    resp = client.messages.create(
        model="claude-sonnet-5",
        max_tokens=1024,
        system=system,
        tools=[RUN_PROCEDURE_TOOL],
        messages=messages,
    )

    tool_calls = [b for b in resp.content if b.type == "tool_use"]
    if not tool_calls:
        return resp.content[0].text

    messages.append({"role": "assistant", "content": resp.content})
    tool_results = []
    for tc in tool_calls:
        if tc.name == "run_procedure":
            proc = load_procedure(tc.input["procedure_name"])
            if proc is None:
                result = f"Unknown procedure: {tc.input['procedure_name']}"
            else:
                outcome = execute_procedure(proc, lambda t, a: f"[{t}({a})]",
                                            context=tc.input.get("context", {}))
                result = proc.to_prompt_block() + f"\n\nStatus: {'SUCCESS' if outcome.success else 'FAILED'}"
            tool_results.append({"type": "tool_result", "tool_use_id": tc.id, "content": result})

    messages.append({"role": "user", "content": tool_results})
    final = client.messages.create(
        model="claude-sonnet-5", max_tokens=1024, system=system,
        tools=[RUN_PROCEDURE_TOOL], messages=messages,
    )
    return final.content[0].text
